64	function buildChatChannelMetaById(): Record<ChatChannelId, ChatChannelMeta> {
65	  const entries = new Map<ChatChannelId, ChatChannelMeta>();
66	
67	  for (const entry of listBundledPluginMetadata({
68	    includeChannelConfigs: true,
69	    includeSyntheticChannelConfigs: false,
70	  })) {
71	    const channel =
72	      entry.packageManifest && "channel" in entry.packageManifest
73	        ? entry.packageManifest.channel
74	        : undefined;
75	    if (!channel) {
76	      continue;
77	    }
78	    const rawId = channel?.id?.trim();
79	    if (!rawId || !CHAT_CHANNEL_ID_SET.has(rawId)) {
80	      continue;
81	    }
82	    const id = rawId as ChatChannelId;
83	    entries.set(
84	      id,
85	      toChatChannelMeta({
86	        id,
87	        channel,
88	      }),
89	    );
90	  }
91	
92	  const missingIds = CHAT_CHANNEL_ORDER.filter((id) => !entries.has(id));
93	  if (missingIds.length > 0) {
94	    throw new Error(`Missing bundled chat channel metadata for: ${missingIds.join(", ")}`);
95	  }
96	
97	  return Object.freeze(Object.fromEntries(entries)) as Record<ChatChannelId, ChatChannelMeta>;
98	}
